*/
void clock_show_date() {
  display.home();
  clock_print_2_digits(datetime.tm_mday);
  clock_print_2_digits(datetime.tm_mon);
  clock_print_2_digits(timelib_tm2y2k(datetime.tm_year));
}
/**
